fn fast_power(base: Int, exp: Int, mod: Int) -> Int:
    var result: Int = 1
    var b = base % mod
    var e = exp
    while e > 0:
        if e & 1:
            result = result * b % mod
        b = b * b % mod
        e >>= 1
    return result
